B.amx=new A.ha("Son g\xfcncelleme: 18 Mart 2026",null)
B.an0=new A.hx("Hizmet Tan\u0131m\u0131",null)
B.amq=new A.ha("Koala, yapay zeka destekli bir mekan analiz uygulamas\u0131d\u0131r. Kullan\u0131c\u0131lar soru foto\u011fraf\u0131 \xe7ekerek ad\u0131m ad\u0131m \xe7\xf6z\xfcm alabilir. Uygulama 9 farkl\u0131 bran\u015fta AI destekli \xf6\u011fretim hizmeti sunar.",null)
B.amX=new A.hx("Hesap ve Kay\u0131t",null)
